// // This module counts down when 'up' is high and counts up when 'up' is low.
module counter(
    input clk,
    input reset,
    input up,
    output reg [3:0] count);always @(posedge clk)
    if (reset)
        count <= 0;
    else if (up)
        count <= count + 1;
    else
        count <= count - 1;

endmodule
